"use strict";(self.webpackChunkdocs=self.webpackChunkdocs||[]).push([[13683],{87423:(e,i,n)=>{n.r(i),n.d(i,{data:()=>r});const r={key:"v-9f84bd06",path:"/C#/Winform/Windows%E6%9C%8D%E5%8A%A1%E7%A8%8B%E5%BA%8F.html",title:"一、创建一个Windows Service",lang:"zh-CN",frontmatter:{},excerpt:"",headers:[{level:2,title:"1）创建Windows Service项目",slug:"_1-创建windows-service项目",children:[]},{level:2,title:"2）对Service重命名",slug:"_2-对service重命名",children:[]},{level:2,title:"1）添加安装程序",slug:"_1-添加安装程序",children:[]},{level:2,title:"2）修改安装服务名",slug:"_2-修改安装服务名",children:[]},{level:2,title:"3）修改安装权限",slug:"_3-修改安装权限",children:[]},{level:2,title:"1）打开ServiceTest代码",slug:"_1-打开servicetest代码",children:[]},{level:2,title:"2）写入Service逻辑",slug:"_2-写入service逻辑",children:[]},{level:2,title:"1）安装脚本Install.bat",slug:"_1-安装脚本install-bat",children:[]},{level:2,title:"2）卸载脚本Uninstall.bat",slug:"_2-卸载脚本uninstall-bat",children:[]},{level:2,title:"3）安装脚本说明",slug:"_3-安装脚本说明",children:[]},{level:2,title:"4）脚本调试",slug:"_4-脚本调试",children:[]},{level:2,title:"0）配置目录结构",slug:"_0-配置目录结构",children:[]},{level:2,title:"1）安装",slug:"_1-安装",children:[]},{level:2,title:"2）卸载",slug:"_2-卸载",children:[]},{level:2,title:"3）启动",slug:"_3-启动",children:[]},{level:2,title:"4）停止",slug:"_4-停止",children:[]},{level:2,title:"5）暂停/继续",slug:"_5-暂停-继续",children:[]},{level:2,title:"6）检查状态",slug:"_6-检查状态",children:[]},{level:2,title:"1）安装并运行服务",slug:"_1-安装并运行服务",children:[]},{level:2,title:"2）附加进程",slug:"_2-附加进程",children:[]},{level:2,title:"3）在代码中加入断点进行调试",slug:"_3-在代码中加入断点进行调试",children:[]}],git:{updatedTime:1655779244e3,contributors:[{name:"panzhiyue",email:"30484534+panzhiyue@users.noreply.github.com",commits:1}]},filePathRelative:"C#/Winform/Windows服务程序.md"}},2303:(e,i,n)=>{n.r(i),n.d(i,{default:()=>t});const r=(0,n(57293).uE)('<p>本文介绍了如何用C#创建、安装、启动、监控、卸载简单的Windows Service 的内容步骤和注意事项。</p><h1 id="一、创建一个windows-service" tabindex="-1"><a class="header-anchor" href="#一、创建一个windows-service" aria-hidden="true">#</a> 一、创建一个Windows Service</h1><h2 id="_1-创建windows-service项目" tabindex="-1"><a class="header-anchor" href="#_1-创建windows-service项目" aria-hidden="true">#</a> 1）创建Windows Service项目</h2><p><img src="https://pzy-images.oss-cn-hangzhou.aliyuncs.com/img/202206210928991.jpg" alt="img"></p><h2 id="_2-对service重命名" tabindex="-1"><a class="header-anchor" href="#_2-对service重命名" aria-hidden="true">#</a> 2）对Service重命名</h2><p>将Service1重命名为你服务名称，这里我们命名为ServiceTest。</p><h1 id="二、创建服务安装程序" tabindex="-1"><a class="header-anchor" href="#二、创建服务安装程序" aria-hidden="true">#</a> 二、创建服务安装程序</h1><h2 id="_1-添加安装程序" tabindex="-1"><a class="header-anchor" href="#_1-添加安装程序" aria-hidden="true">#</a> 1）添加安装程序</h2><p><img src="https://pzy-images.oss-cn-hangzhou.aliyuncs.com/img/202206210928988.jpg" alt="img"></p><p><img src="https://pzy-images.oss-cn-hangzhou.aliyuncs.com/img/202206210928997.jpg" alt="img"></p><p>之后我们可以看到上图，自动为我们创建了ProjectInstaller.cs以及2个安装的组件</p><h2 id="_2-修改安装服务名" tabindex="-1"><a class="header-anchor" href="#_2-修改安装服务名" aria-hidden="true">#</a> 2）修改安装服务名</h2><p>右键serviceInsraller1，选择属性，将ServiceName的值改为ServiceTest。</p><p><img src="https://pzy-images.oss-cn-hangzhou.aliyuncs.com/img/202206210928998.jpg" alt="img"></p><h2 id="_3-修改安装权限" tabindex="-1"><a class="header-anchor" href="#_3-修改安装权限" aria-hidden="true">#</a> 3）修改安装权限</h2><p>右键serviceProcessInsraller1，选择属性，将Account的值改为LocalSystem。</p><p><img src="https://pzy-images.oss-cn-hangzhou.aliyuncs.com/img/202206210928000.jpg" alt="img"></p><h1 id="三、写入服务代码" tabindex="-1"><a class="header-anchor" href="#三、写入服务代码" aria-hidden="true">#</a> 三、写入服务代码</h1><h2 id="_1-打开servicetest代码" tabindex="-1"><a class="header-anchor" href="#_1-打开servicetest代码" aria-hidden="true">#</a> 1）打开ServiceTest代码</h2><p>右键ServiceTest，选择查看代码。</p><h2 id="_2-写入service逻辑" tabindex="-1"><a class="header-anchor" href="#_2-写入service逻辑" aria-hidden="true">#</a> 2）写入Service逻辑</h2><div class="language-c# ext-c# line-numbers-mode"><pre class="language-c#"><code>using System;\nusing System.Collections.Generic;\nusing System.ComponentModel;\nusing System.Data;\nusing System.Diagnostics;\nusing System.Linq;\nusing System.ServiceProcess;\nusing System.Text;\nusing System.Data.SqlClient;\n\nnamespace DataBaseService\n{\npublic partial class DataBakService : ServiceBase\n{\npublic DataBakService()\n{\nInitializeComponent();\n}\n\n//定时器\nSystem.Timers.Timer tmBak = new System.Timers.Timer();\n//服务器启动时写日志、开启定时器\nprotected override void OnStart(string[] args)\n{\nusing (System.IO.StreamWriter sw = new System.IO.StreamWriter(&quot;D:\\\\log.txt&quot;, true))\n{\nsw.WriteLine(DateTime.Now.ToString(&quot;yyyy-MM-dd HH:mm:ss&quot;) + &quot; DATABASENAME Service Start.&quot;);\n}\n\n//到时间的时候执行事件\n\ntmBak.Interval = 60000;//一分钟执行一次\ntmBak.AutoReset = true;//执行一次 false，一直执行true\n//是否执行System.Timers.Timer.Elapsed事件\ntmBak.Enabled = true;\ntmBak.Start();\ntmBak.Elapsed += new System.Timers.ElapsedEventHandler(SQLBak);\n\n}\n\nprivate void SQLBak(object source, System.Timers.ElapsedEventArgs e)\n{\n//如果当前时间是10点30分\nif (DateTime.Now.Hour == 9 &amp;&amp; DateTime.Now.Minute == 50)\n{\nstring sql = string.Format(@&quot;\nBACKUP DATABASE DATABASENAME \nTO DISK = N&#39;E:\\DBBak\\DATABASENAME {0}{1}{2}.bak&#39;--目录一定要存在\nWITH INIT , NOUNLOAD ,\nNAME = N&#39;数据库备份&#39;, --名字随便取\nNOSKIP ,\nSTATS = 10,\nNOFORMAT&quot;, DateTime.Now.Year,DateTime.Now.Month,DateTime.Now.Day);\ntry\n{\nusing (System.IO.StreamWriter sw = new System.IO.StreamWriter(&quot;D:\\\\log.txt&quot;, true))\n{\nsw.WriteLine(DateTime.Now.ToString(&quot;yyyy-MM-dd HH:mm:ss&quot;) + &quot; 正在备份DATABASENAME 数据库......&quot;);\n}\n\nSqlConnection conn = new SqlConnection(&quot;server=127.0.0.1;uid=sa;pwd=44545454;database=DATABASENAME &quot;);\nconn.Open();\nSqlCommand cmd = new SqlCommand(sql, conn);\ncmd.CommandTimeout = 0;\ncmd.ExecuteNonQuery();\nconn.Close();\n\n\n}\ncatch (Exception ex)\n{\nusing (System.IO.StreamWriter sw = new System.IO.StreamWriter(&quot;D:\\\\log.txt&quot;, true))\n{\nsw.WriteLine(DateTime.Now.ToString(&quot;yyyy-MM-dd HH:mm:ss&quot;) + &quot; 备份DATABASENAME 数据库出现异常：&quot; + ex.Message);\nreturn;\n}\n}\n\nusing (System.IO.StreamWriter sw = new System.IO.StreamWriter(&quot;D:\\\\log.txt&quot;, true))\n{\nsw.WriteLine(DateTime.Now.ToString(&quot;yyyy-MM-dd HH:mm:ss&quot;) + &quot; 备份DATABASENAME 数据库成功！&quot;);\n}\n\n\n}\n\n}\n\n\n//服务停止时写日志\nprotected override void OnStop()\n{\nusing (System.IO.StreamWriter sw = new System.IO.StreamWriter(&quot;D:\\\\log.txt&quot;, true))\n{\nsw.WriteLine(DateTime.Now.ToString(&quot;yyyy-MM-dd HH:mm:ss&quot;) + &quot; DATABASENAME \n\nService Stop.&quot;);\n}\n}\n\n}\n}\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>这是一个备份数据库的服务，逻辑很简单，就是通过定时器实现在特定的时间执行SQL语句备份数据库，并将每一步操作的情况写入日志文件。</p><h1 id="四、创建安装脚本" tabindex="-1"><a class="header-anchor" href="#四、创建安装脚本" aria-hidden="true">#</a> 四、创建安装脚本</h1><p>在项目中添加2个文件如下(必须是ANSI或者UTF-8无BOM格式)：</p><h2 id="_1-安装脚本install-bat" tabindex="-1"><a class="header-anchor" href="#_1-安装脚本install-bat" aria-hidden="true">#</a> 1）安装脚本Install.bat</h2><div class="language-bash ext-sh line-numbers-mode"><pre class="language-bash"><code>%SystemRoot%\\Microsoft.NET\\Framework\\v4.0.30319\\installutil.exe D:\\dbback\\EFNETSYSDBBAK\\DataBaseService.exe\nNet Start ServiceEFNETSYS\nsc config ServiceEFNETSYS start= auto\npause\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="_2-卸载脚本uninstall-bat" tabindex="-1"><a class="header-anchor" href="#_2-卸载脚本uninstall-bat" aria-hidden="true">#</a> 2）卸载脚本Uninstall.bat</h2><div class="language-bash ext-sh line-numbers-mode"><pre class="language-bash"><code>%SystemRoot%\\Microsoft.NET\\Framework\\v4.0.30319\\installutil.exe /u D:\\dbback\\EFNETSYSDBBAK\\DataBaseService.exe\npause\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="_3-安装脚本说明" tabindex="-1"><a class="header-anchor" href="#_3-安装脚本说明" aria-hidden="true">#</a> 3）安装脚本说明</h2><p>第二行为启动服务。</p><p>第三行为设置服务为自动运行。</p><p>这2行视服务形式自行选择。</p><h2 id="_4-脚本调试" tabindex="-1"><a class="header-anchor" href="#_4-脚本调试" aria-hidden="true">#</a> 4）脚本调试</h2><p>如果需要查看脚本运行状况，在脚本最后一行加入pause</p><h1 id="五、在c-中对服务进行控制" tabindex="-1"><a class="header-anchor" href="#五、在c-中对服务进行控制" aria-hidden="true">#</a> 五、在C#中对服务进行控制</h1><h2 id="_0-配置目录结构" tabindex="-1"><a class="header-anchor" href="#_0-配置目录结构" aria-hidden="true">#</a> 0）配置目录结构</h2><p>建立一个新WPF项目，叫WindowsServiceTestUI，添加对System.ServiceProcess的引用。</p><p>在WindowsServiceTestUI的bin\\Debug目录下建立Service目录。</p><p>将WindowsServiceTest的生成目录设置为上面创建的Service目录。</p><p>生成后目录结构如下图</p><p><img src="https://pzy-images.oss-cn-hangzhou.aliyuncs.com/img/202206210928001.jpg" alt="img"></p><h2 id="_1-安装" tabindex="-1"><a class="header-anchor" href="#_1-安装" aria-hidden="true">#</a> 1）安装</h2><p>安装时会产生目录问题，所以安装代码如下：</p><table><thead><tr><th>12345678</th><th>string CurrentDirectory = System.Environment.CurrentDirectory;System.Environment.CurrentDirectory = CurrentDirectory + &quot;\\Service&quot;;Process process = new Process();process.StartInfo.UseShellExecute = false;process.StartInfo.FileName = &quot;Install.bat&quot;;process.StartInfo.CreateNoWindow = true;process.Start();System.Environment.CurrentDirectory = CurrentDirectory;</th></tr></thead><tbody><tr><td></td><td></td></tr></tbody></table><h2 id="_2-卸载" tabindex="-1"><a class="header-anchor" href="#_2-卸载" aria-hidden="true">#</a> 2）卸载</h2><p>卸载时也会产生目录问题，所以卸载代码如下：</p><table><thead><tr><th>12345678</th><th>string CurrentDirectory = System.Environment.CurrentDirectory;System.Environment.CurrentDirectory = CurrentDirectory + &quot;\\Service&quot;;Process process = new Process();process.StartInfo.UseShellExecute = false;process.StartInfo.FileName = &quot;Uninstall.bat&quot;;process.StartInfo.CreateNoWindow = true;process.Start();System.Environment.CurrentDirectory = CurrentDirectory;</th></tr></thead><tbody><tr><td></td><td></td></tr></tbody></table><h2 id="_3-启动" tabindex="-1"><a class="header-anchor" href="#_3-启动" aria-hidden="true">#</a> 3）启动</h2><p>代码如下：</p><table><thead><tr><th>12345</th><th>using System.ServiceProcess; ServiceController serviceController = new ServiceController(&quot;ServiceTest&quot;);serviceController.Start();</th></tr></thead><tbody><tr><td></td><td></td></tr></tbody></table><h2 id="_4-停止" tabindex="-1"><a class="header-anchor" href="#_4-停止" aria-hidden="true">#</a> 4）停止</h2><table><thead><tr><th>123</th><th>ServiceController serviceController = new ServiceController(&quot;ServiceTest&quot;);if (serviceController.CanStop) serviceController.Stop();</th></tr></thead><tbody><tr><td></td><td></td></tr></tbody></table><h2 id="_5-暂停-继续" tabindex="-1"><a class="header-anchor" href="#_5-暂停-继续" aria-hidden="true">#</a> 5）暂停/继续</h2><table><thead><tr><th>12345678</th><th>ServiceController serviceController = new ServiceController(&quot;ServiceTest&quot;);if (serviceController.CanPauseAndContinue){ if (serviceController.Status == ServiceControllerStatus.Running) serviceController.Pause(); else if (serviceController.Status == ServiceControllerStatus.Paused) serviceController.Continue();}</th></tr></thead><tbody><tr><td></td><td></td></tr></tbody></table><h2 id="_6-检查状态" tabindex="-1"><a class="header-anchor" href="#_6-检查状态" aria-hidden="true">#</a> 6）检查状态</h2><table><thead><tr><th>12</th><th>ServiceController serviceController = new ServiceController(&quot;ServiceTest&quot;);string Status = serviceController.Status.ToString();</th></tr></thead><tbody><tr><td></td><td></td></tr></tbody></table><h1 id="六、调试windows-service" tabindex="-1"><a class="header-anchor" href="#六、调试windows-service" aria-hidden="true">#</a> 六、调试Windows Service</h1><h2 id="_1-安装并运行服务" tabindex="-1"><a class="header-anchor" href="#_1-安装并运行服务" aria-hidden="true">#</a> 1）安装并运行服务</h2><h2 id="_2-附加进程" tabindex="-1"><a class="header-anchor" href="#_2-附加进程" aria-hidden="true">#</a> 2）附加进程</h2><p><img src="https://pzy-images.oss-cn-hangzhou.aliyuncs.com/img/202206210928423.jpg" alt="img"></p><p><img src="https://pzy-images.oss-cn-hangzhou.aliyuncs.com/img/202206210928433.jpg" alt="img"></p><h2 id="_3-在代码中加入断点进行调试" tabindex="-1"><a class="header-anchor" href="#_3-在代码中加入断点进行调试" aria-hidden="true">#</a> 3）在代码中加入断点进行调试</h2><p><img src="https://pzy-images.oss-cn-hangzhou.aliyuncs.com/img/202206210928441.jpg" alt="img"></p><h1 id="七、总结" tabindex="-1"><a class="header-anchor" href="#七、总结" aria-hidden="true">#</a> 七、总结</h1><p>本文对Windows service的上述配置都未做详细解释，但是按上述步骤就可以制作可运行的Windows Service，从而达到了工作的需求。</p>',66),s={},t=(0,n(63243).Z)(s,[["render",function(e,i){return r}]])},63243:(e,i)=>{i.Z=(e,i)=>{const n=e.__vccOpts||e;for(const[e,r]of i)n[e]=r;return n}}}]);